library(shiny)

ui &lt;- fluidPage(
  titlePanel("Simple MPG App"),

  sidebarLayout(
    sidebarPanel(
      selectInput(
        inputId = "selected_class",
        label = "Choose a vehicle class:",
        choices = unique(mpg$class)
      )
    ),

    mainPanel(
      plotOutput("mpg_plot")
    )
  )
)

server &lt;- function(input, output) {
  output$mpg_plot &lt;- renderPlot({
    mpg |&gt;
      filter(class == input$selected_class) |&gt;
      ggplot(aes(x = cty, y = hwy)) +
      geom_point() +
      labs(
        title = "City MPG vs. Highway MPG",
        x = "City MPG",
        y = "Highway MPG"
      )
  })
}

shinyApp(ui = ui, server = server)
